mapper.select:
SELECT BRAND_NO, BRAND_NM, BRAND_IMG_URL, USE_YN
FROM PR_BRAND_BASE
WHERE BRAND_NO = #{brandNo}

SELECT DLV_POLICY_NO, DLV_POLICY_NM, DLV_TP_CD, DLV_AMT, FREE_COND_AMT, RTN_DLV_AMT, USE_YN
FROM PR_DLV_POLICY
WHERE DLV_POLICY_NO = #{dlvPolicyNo}

SELECT OPT_GRP_CD, OPT_GRP_NM, SORT_ORD, USE_YN
FROM PR_OPT_GRP
WHERE OPT_GRP_CD = #{optGrpCd}

SELECT OPT_GRP_CD, OPT_ITM_CD, OPT_ITM_NM, SORT_ORD, USE_YN
FROM PR_OPT_ITM
WHERE OPT_GRP_CD = #{optGrpCd}
  AND OPT_ITM_CD = #{optItmCd}

